// app/Models/Autor.php
class Autor extends Model
{
    // Um autor tem muitos livros
    public function livros()
    {
        return $this->hasMany(Livro::class);
    }
}

// app/Models/Livro.php
class Livro extends Model
{
    // Um livro pertence a um autor
    public function autor()
    {
        return $this->belongsTo(Autor::class);
    }
}

// Buscar todos os livros de um autor
$autor = Autor::find(1);
$livros = $autor->livros; // Executa o SELECT automaticamente

// Eager Loading — evita N+1 queries
$autores = Autor::with('livros')->get();

foreach ($autores as $autor) {
    // Sem N+1! Os livros já foram carregados
    echo $autor->livros->count();
}

// Criar livro já associado ao autor
$autor->livros()->create([
    'titulo' => 'Laravel na Prática',
    'preco'  => 59.90,
]);
